int findContentChildren(vector<int>& g, vector<int>& s)
{
    sort(g.begin(), g.end());
    sort(s.begin(), s.end());

    vector<bool> used(s.size(), false);
    int content = 0;

    for (int need : g)
    {
        int bestIndex = -1;
        for (int j = 0; j < (int)s.size(); j++)
            if (!used[j] && s[j] >= need)
            {
                if (bestIndex == -1 || s[j] < s[bestIndex]) bestIndex = j;
            }
        if (bestIndex != -1)
        {
            used[bestIndex] = true;
            content++;
        }
    }
    return content;
}

int main()
{
    vector<int> g = {1, 2, 3};
    vector<int> s = {1, 1};

    cout << findContentChildren(g, s);

    return 0;
}

