bool canJumpFrom(int pos, vector<int>& nums)
{
    if (pos >= (int)nums.size() - 1) return true;

    int maxJump = min((int)nums.size() - 1, pos + nums[pos]);
    for (int next = pos + 1; next <= maxJump; next++)
        if (canJumpFrom(next, nums)) return true;

    return false;
}

