int minJumpsFrom(int pos, vector<int>& nums)
{
    if (pos >= (int)nums.size() - 1) return 0;

    int best = INT_MAX;
    int maxJump = min((int)nums.size() - 1, pos + nums[pos]);
    for (int next = pos + 1; next <= maxJump; next++)
    {
        int sub = minJumpsFrom(next, nums);
        if (sub != INT_MAX) best = min(best, sub + 1);
    }
    return best;
}

