#include <unordered_set>
#include <algorithm>

using namespace std;

vector<int> partitionLabels(string s)
{
    vector<int> result;
    int n = s.size();
    int start = 0;

    while (start < n)
    {
        unordered_set<char> inPartition;
        int end = start;

        int i = start;
        while (i <= end)
        {
            inPartition.insert(s[i]);
            for (int j = i + 1; j < n; j++)
                if (inPartition.count(s[j])) end = max(end, j);
            i++;
        }

        result.push_back(end - start + 1);
        start = end + 1;
    }
    return result;
}

int main()
{
    string s = "ababcbacadefegdehijhklij";
    vector<int> result = partitionLabels(s);
    for (int r : result) cout << r << " ";

    return 0;
}

